SELECT [Cust_ Ledger Entry].[Customer No_], [Cust_ Ledger Entry].[Payment Method Code], [Cust_ Ledger Entry].[Closed at Date], [Cust_ Ledger Entry].[Due Date], [Cust_ Ledger Entry].[Posting Date], Sum(Val([Detailed Cust_ Ledg_ Entry.Amount])) AS IMPORTO, [Geographical Zone].Description, [Geographical Zone_1].Description, [Cust_ Ledger Entry].[Global Dimension 1 Code], [Cust_ Ledger Entry].[Global Dimension 2 Code]
FROM ((([Cust_ Ledger Entry] INNER JOIN [Detailed Cust_ Ledg_ Entry] ON [Cust_ Ledger Entry].[Entry No_] = [Detailed Cust_ Ledg_ Entry].[Cust_ Ledger Entry No_]) INNER JOIN Customer ON [Cust_ Ledger Entry].[Customer No_] = Customer.No_) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code
WHERE ((([Detailed Cust_ Ledg_ Entry].[Entry Type])=1) AND (([Detailed Cust_ Ledg_ Entry].[Document Type])=2))
GROUP BY [Cust_ Ledger Entry].[Customer No_], [Cust_ Ledger Entry].[Payment Method Code], [Cust_ Ledger Entry].[Closed at Date], [Cust_ Ledger Entry].[Due Date], [Cust_ Ledger Entry].[Posting Date], [Geographical Zone].Description, [Geographical Zone_1].Description, [Cust_ Ledger Entry].[Global Dimension 1 Code], [Cust_ Ledger Entry].[Global Dimension 2 Code]
HAVING ((([Cust_ Ledger Entry].[Payment Method Code])="INSOL" Or ([Cust_ Ledger Entry].[Payment Method Code])="RIBA") AND (([Cust_ Ledger Entry].[Due Date])=#5/31/2024# Or ([Cust_ Ledger Entry].[Due Date])=#5/31/2023# Or ([Cust_ Ledger Entry].[Due Date])=#5/31/2022# Or ([Cust_ Ledger Entry].[Due Date])=#5/31/2021#));

